local enabled = false
local overlay = nil
local fading = false

local function safeNotify(message, title, duration)
    if notify then
        pcall(notify, message, title or "Movement Toggle", duration or 3)
    end
end

local function getViewportSize()
    local ok, size = pcall(function()
        return workspace.CurrentCamera.ViewportSize
    end)

    if ok and size then
        return size
    end

    return Vector2.new(1920, 1080)
end

local function createDrawingOverlay()
    local cache = {}
    local palette = IMAGE_DATA.Palette

    for i = 1, #IMAGE_DATA.X do
        local rect = Drawing.new("Square")
        rect.Visible = false
        rect.Filled = true
        rect.Color = palette[IMAGE_DATA.C[i]]
        rect.Transparency = 1
        rect.ZIndex = 1000
        table.insert(cache, rect)
    end

    local group = {
        Cache = cache,
        Visible = false,
        Transparency = 1,
        LastW = 0,
        LastH = 0,
    }

    function group:SetVisible(value)
        self.Visible = value == true
        for _, rect in ipairs(self.Cache) do
            rect.Visible = self.Visible
        end
    end

    function group:SetTransparency(value)
        self.Transparency = value
        for _, rect in ipairs(self.Cache) do
            rect.Transparency = value
        end
    end

    function group:Layout()
        local viewport = getViewportSize()
        local sx = viewport.X / IMAGE_W
        local sy = viewport.Y / IMAGE_H

        if self.LastW == viewport.X and self.LastH == viewport.Y then
            return
        end

        self.LastW = viewport.X
        self.LastH = viewport.Y

        for i, rect in ipairs(self.Cache) do
            rect.Position = Vector2.new(IMAGE_DATA.X[i] * sx, IMAGE_DATA.Y[i] * sy)
            rect.Size = Vector2.new(math.ceil(IMAGE_DATA.W[i] * sx) + 1, math.ceil(IMAGE_DATA.H[i] * sy) + 1)
        end
    end

    function group:Remove()
        for _, rect in ipairs(self.Cache) do
            pcall(function()
                rect:Remove()
            end)
        end
        self.Cache = {}
    end

    return group
end

local function showOverlay()
    fading = false

    if not overlay then
        overlay = createDrawingOverlay()
    end

    overlay:Layout()
    overlay:SetTransparency(0)
    overlay:SetVisible(true)

    task.spawn(function()
        local duration = 0.45
        local started = os.clock()

        while enabled and os.clock() - started < duration do
            local alpha = (os.clock() - started) / duration
            if overlay then
                overlay:SetTransparency(alpha)
            end
            task.wait(0.016)
        end

        if enabled and overlay then
            overlay:SetTransparency(1)
        end
    end)
end

local function fadeOutOverlay()
    if not overlay or fading then return end

    fading = true
    task.spawn(function()
        local duration = 0.45
        local started = os.clock()

        while os.clock() - started < duration do
            local alpha = 1 - ((os.clock() - started) / duration)
            if overlay then
                overlay:SetTransparency(alpha)
            end
            task.wait(0.016)
        end

        if overlay then
            overlay:SetTransparency(0)
            overlay:SetVisible(false)
        end

        fading = false
    end)
end

local function tapKey(vk, seconds)
    pcall(keypress, vk)
    task.wait(seconds or PULSE_SECONDS)
    pcall(keyrelease, vk)
end

local function setEnabled(value)
    enabled = value == true

    if enabled then
        showOverlay()
        safeNotify("Enabled", "Movement Toggle", 2)
    else
        fadeOutOverlay()
        safeNotify("Disabled", "Movement Toggle", 2)
    end
end

task.spawn(function()
    local wasDown = false

    while true do
        local down = false
        pcall(function()
            down = iskeypressed(VK_RCONTROL) == true
        end)

        if down and not wasDown then
            setEnabled(not enabled)
        end

        wasDown = down
        task.wait(0.03)
    end
end)

task.spawn(function()
    math.randomseed(math.floor(os.clock() * 100000))

    while true do
        if enabled then
            if overlay then
                overlay:Layout()
            end

            local vk = MOVE_KEYS[math.random(1, #MOVE_KEYS)]
            tapKey(vk, PULSE_SECONDS)
            task.wait(math.random(650, 1200) / 100)
        else
            task.wait(0.1)
        end
    end
end)

safeNotify("Loaded. Press Right Control to toggle.", "Movement Toggle", 4)
